type BureauAccountSnapshot = Pick<
  typeof creditAccounts.$inferSelect,
  | 'creditorName'
  | 'accountNumber'
  | 'onTransunion'
  | 'onExperian'
  | 'onEquifax'
  | 'transunionBalance'
  | 'experianBalance'
  | 'equifaxBalance'
>;

function buildAccountBalanceDiscrepancies(
  clientId: string,
  accounts: BureauAccountSnapshot[]
): Array<typeof bureauDiscrepancies.$inferInsert> {
  const discrepancies: Array<typeof bureauDiscrepancies.$inferInsert> = [];

  for (const account of accounts) {
    const bureauBalances = [
      account.onTransunion ? account.transunionBalance : null,
      account.onExperian ? account.experianBalance : null,
      account.onEquifax ? account.equifaxBalance : null,
    ].filter((balance): balance is number => balance !== null);

    if (bureauBalances.length < 2) {
      continue;
    }

    if (new Set(bureauBalances).size > 1) {
      discrepancies.push({
        id: randomUUID(),
        clientId,
        discrepancyType: 'account_balance',
        field: 'balance',
        creditorName: account.creditorName,
        accountNumber: account.accountNumber,
        valueTransunion: account.onTransunion ? account.transunionBalance?.toString() || null : null,
        valueExperian: account.onExperian ? account.experianBalance?.toString() || null : null,
        valueEquifax: account.onEquifax ? account.equifaxBalance?.toString() || null : null,
        severity: 'medium',
        isDisputable: true,
        disputeRecommendation: 'Balance differs across bureaus within this report pull. Request verification from the reporting bureaus.',
        createdAt: new Date(),
      });
    }
  }

  return discrepancies;
}

async function detectBureauDiscrepancies(clientId: string, creditReportId: string): Promise<void> {
  const allAccounts = await db
    .select()
    .from(creditAccounts)
    .where(and(eq(creditAccounts.clientId, clientId), eq(creditAccounts.creditReportId, creditReportId)));

  const allProfiles = await db
    .select()
    .from(consumerProfiles)
    .where(and(eq(consumerProfiles.clientId, clientId), eq(consumerProfiles.creditReportId, creditReportId)));

  // Clear existing discrepancies for this client before writing the latest pull snapshot.
  await db.delete(bureauDiscrepancies).where(eq(bureauDiscrepancies.clientId, clientId));

  const accountDiscrepancies = buildAccountBalanceDiscrepancies(clientId, allAccounts);
  if (accountDiscrepancies.length > 0) {
    await db.insert(bureauDiscrepancies).values(accountDiscrepancies);
  }

  await detectPiiDiscrepancies(clientId, allProfiles);
}

export { buildAccountBalanceDiscrepancies };

